import pytest
from moo.core import code, parse
from moo.sdk import lookup


def test_exit_traversal_north(t_wizard, zork_world):
    room = lookup("West of House")
    t_wizard.location = room
    t_wizard.save()
    printed = []
    with code.ContextManager(t_wizard, printed.append):
        parse.interpret(t_wizard, "north")
    t_wizard.refresh_from_db()
    assert t_wizard.location.name == "North of House"


